1	import { execSync } from 'node:child_process';
2	
3	/**
4	 * Runs once before any Playwright tests. Seeds the test database so every
5	 * test run starts from a known, deterministic state regardless of how
6	 * playwright is invoked (npx playwright test, CI, etc.).
7	 *
8	 * Schema sync (prisma db push) must happen BEFORE the web server starts to
9	 * avoid disrupting its connection pool. It is NOT done here:
10	 *   - Local: run `npm run setup:playwright` once after docker setup or schema
11	 *     changes, then `npm run build`.
12	 *   - CI: the workflow runs `prisma db push` and `npm run build` before tests.
13	 *
14	 * This function only inserts/replaces data, which is safe while the server
15	 * is running.
16	 *
17	 * When SKIP_DB_SEED is set, the full seed is skipped - used by CI when the
18	 * `db` container was started from a pre-seeded image (see
19	 * .github/workflows/publish-seeded-db-image.yml) rather than a bare
20	 * `mariadb:lts`, so the data is already there. `prisma db push` still runs as
21	 * a separate CI step regardless, so schema changes on a branch not yet
22	 * baked into that image are still applied correctly.
23	 *
24	 * That image is only rebuilt when prisma/schema.prisma or prisma/seed.ci.ts
25	 * change, so the single "upcoming" game day it bakes in goes stale as real
26	 * time passes it - once its date is in the past, gameDayService.getUpcoming()
27	 * finds no game at all and invitation-sending is skipped regardless of the
28	 * override flag. So even when the full seed is skipped, that one row's date
29	 * is still re-pointed at the next Friday from now.
30	 */
31	export default function globalSetup() {
32	    if (process.env.SKIP_DB_SEED) {
33	        console.log('⚙️  Refreshing upcoming game day on pre-seeded image...');
34	        if (process.env.CI) {
35	            execSync('npm run refresh:upcoming-gameday:ci', { stdio: 'inherit' });
36	        } else {
37	            execSync('npm run refresh:upcoming-gameday:playwright', { stdio: 'inherit' });
38	        }
39	        console.log('✅ Upcoming game day refreshed');
40	        return;
41	    }
42	
43	    console.log('⚙️  Seeding test database...');
44	    if (process.env.CI) {
45	        execSync('npm run seed:ci', { stdio: 'inherit' });
46	    } else {
47	        execSync('npm run seed:playwright', { stdio: 'inherit' });
48	    }
49	    console.log('✅ Test database ready');
50	}
